const Handle_Print = {

    handleCmdData(event){
        try {
            // Extract the JSON part
            const jsonStr = event.data.replace('[cmd][data] ', '');
            const history = JSON.parse(jsonStr);
            
            // Display the latest values
            if (history.rounds.length > 0) {
                const latestRound = history.rounds[history.rounds.length - 1];
                const latestAcc = history.global_acc[history.global_acc.length - 1] * 100;
                const latestTime = history.total_time[history.total_time.length - 1];
                
                let accDisplay = latestAcc.toFixed(2) + '%';
                if (history.global_acc.length >= 2) {
                    const previousAcc = history.global_acc[history.global_acc.length - 2] * 100;
                    const accDiff = latestAcc - previousAcc;
                    const sign = accDiff > 0 ? '+' : '';
                    accDisplay += ` (${sign}${accDiff.toFixed(2)}%)`;
                }
                
                this.addDataRow(latestRound, accDisplay, latestTime);
                console.log('Rounds:', latestRound, '+ Global accuracies:', latestAcc, '+ Total times:', latestTime);
            }
        } catch (e) {
            console.error('Failed to parse history:', e);
        }
    },

    handleCmdConfig(event){
        try {
            // Extract the JSON part
            const jsonStr = event.data.replace('[cmd][cfg] ', '');
            const config = JSON.parse(jsonStr);
            console.log('Config received:', config);
            for (const key in config){
                const cell = document.querySelector(`.train-setting .${key} .value`);
                cell.innerHTML = this.formatValue(config[key]);
            }
            Handle_UI.showBoard('#server-side #plotGraph' ,"setting-gb");
            Handle_UI.showBoard('#server-side #data-board','setting-db');
            Handle_UI.showBoard('#server-side .train-setting','setting-ts2');
        } catch (e) {
            console.error('Failed to parse config:', e);
        }
    },

    formatValue(value) {
        if (typeof value === 'boolean') {
            return value ? 'True' : 'False';
        }
        if (typeof value === 'string') {
            return `'${value}'`;
        }
        if (value === null) {
            return 'null';
        }
        return String(value);
    },

    getValueType(value) {
        if (value === null) return 'Null';
        if (typeof value === 'boolean') return 'Boolean';
        if (typeof value === 'number') {
            return Number.isInteger(value) ? 'Integer' : 'Float';
        }
        if (typeof value === 'string') return 'String';
        if (Array.isArray(value)) return 'Array';
        if (typeof value === 'object') return 'Object';
        return typeof value;
    },

    handleCmdPlot(event) {
        // Extract both total_rounds and the JSON data
        const match = event.data.match(/total_rounds: (\d+), (.*)/);
        
        if (match) {
            const totalRound = match[1];
            const jsonStr = match[2];
            try {
                const history = JSON.parse(jsonStr);
                // Skip client accuracy curve when simulating robustness experiments
                const skipClientAcc = currentSimulateFile.startsWith('robustness_attack');
                if (skipClientAcc) history._skip_client_acc = true;
                
                // Send history data in POST request
                fetch(`/generate-plot/${totalRound}`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ history: history })
                })
                .then(response => response.blob())
                .then(blob => {
                    const imageUrl = URL.createObjectURL(blob);
                    const img = document.createElement('img');
                    img.src = imageUrl;
                    img.width = 700;
                    img.alt = 'Training Plot';
                    document.getElementById('graph').innerHTML = img.outerHTML;
                    img.onload = () => URL.revokeObjectURL(imageUrl);
                });
            } catch (e) {
                console.error('Failed to parse history:', e);
            }
        }
    },

    handleCmd(event){
        const roundNumber = event.data.match(/current round: (\d+)/);
        const clientNumber = event.data.match(/current client number: (\d+)/);
        const stateLabel = event.data.match(/current state: (.+)$/);
        if(roundNumber){
            document.getElementById(config.roundLabel).innerHTML = roundNumber[1];
        }
        if(clientNumber){
            document.getElementById("connected-client-label").innerHTML = clientNumber[1];
        }
        if (stateLabel){
            document.getElementById(config["stateLabelId"]).innerHTML = stateLabel[1];
        }
    },

    addDataRow(round, accuracy, time) {
        const tbody = document.getElementById('data-board-table');

        const newRow = document.createElement('tr');
        const roundsCell = document.createElement('td');
        const accuracyCell = document.createElement('td');
        const timeCell = document.createElement('td');
        
        roundsCell.textContent = `Round ${round}`;
        accuracyCell.textContent = `${accuracy}`;
        timeCell.textContent = `${time} s`;
        
        newRow.appendChild(roundsCell);
        newRow.appendChild(accuracyCell);
        newRow.appendChild(timeCell);
        tbody.appendChild(newRow);
    },

    addOutputLine(text) {
        let logBox;
        logBox = document.getElementById(config.logsBoxId);    
        const line = document.createElement('p');
        line.textContent = text;
        logBox.appendChild(line);
        logBox.scrollTop = logBox.scrollHeight; // Auto-scroll to bottom
    }
}